// Split one email item (with N binary props) into N items, one per attachment.
// Each output item has a normalised binary key 'file' for the HTTP POST downstream.
// IMAP returns from as plain string: "Name <email@example.com>" or just "email@example.com"
const items = [];
const emailJson = $input.first().json;
const emailBinary = $input.first().binary || {};

const fromRaw = emailJson.from || '';
const senderMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/(\S+@\S+)/);
const sender = senderMatch ? senderMatch[1] : fromRaw;

for (const [key, binaryData] of Object.entries(emailBinary)) {
  items.push({
    json: {
      sender,
      subject: emailJson.subject || '',
      date: emailJson.date || new Date().toISOString(),
      originalFilename: binaryData.fileName || key,
      mimeType: binaryData.mimeType || 'application/octet-stream',
    },
    binary: { file: binaryData },
  });
}

return items;

// Build YAML frontmatter + note body.
// Note name: YYYY-MM-DD + markitdown title (fallback: filename → subject)
const conv = $input.first().json;  // { markdown, title, filename, source_type }
const email = $('Split Attachments').first().json;

// Date from email (ISO string)
const d = new Date(email.date);
const dateStr = isNaN(d.getTime())
  ? new Date().toISOString().split('T')[0]
  : d.toISOString().split('T')[0];

// Title fallback chain: markitdown title → filename stem → email subject → 'untitled'
const rawTitle = (conv.title || '').trim()
  || (email.originalFilename || '').replace(/\.[^.]+$/, '').trim()
  || (email.subject || '').trim()
  || 'untitled';
const safeTitle = rawTitle.replace(/[\/\\:*?"<>|]/g, '-').substring(0, 100).trim();
const noteName = `${dateStr} ${safeTitle}`;
const path = `002 - incoming/${noteName}.md`;

// YAML frontmatter
const subjectSafe = (email.subject || '').replace(/"/g, "'");
const fm = [
  '---',
  `sender: "${email.sender || email.from || ''}"`,
  `subject: "${subjectSafe}"`,
  `received: ${dateStr}`,
  `source_type: ${conv.source_type || 'document'}`,
  '---',
].join('\n');

const content = `${fm}\n\n${conv.markdown || ''}`;

return [{ json: {
  body: JSON.stringify({ path, content, overwrite: false }),
  path,
  markdown: conv.markdown || '',
  noteName,
} }];

const note = $('Build Note Body').first().json;
return [{ json: { body: JSON.stringify({
  id: note.path,
  text: note.markdown,
  collection: 'vault',
  metadata: { source: note.path, type: 'document' },
}) } }];

const note = $('Build Note Body').first().json;
const text = `Email attachment saved:\n<b>${note.noteName}</b>\n\nFolder: 002 - incoming`;
return [{ json: { body: JSON.stringify({
  chat_id: $env.PIPELINE_CHAT_ID,
  text,
  parse_mode: 'HTML',
}) } }];
